SELECT 'KYC PENDING' as type, COUNT(*) as count FROM seller_kyc WHERE status = 'PENDING_REVIEW' UNION ALL SELECT 'KYC ALL' as type, COUNT(*) as count FROM seller_kyc UNION ALL SELECT 'NOTIFICATIONS UNREAD' as type, COUNT(*) as count FROM notifications WHERE read = false AND type = 'SELLER_REVIEW_NEEDED' UNION ALL SELECT 'NOTIFICATIONS TOTAL' as type, COUNT(*) as count FROM notifications WHERE type = 'SELLER_REVIEW_NEEDED' ORDER BY type;
